 80→    public synchronized void resize(final long newCacheSizeBytes) {
 81→        final boolean shrink = newCacheSizeBytes < maxCacheSizeBytes;
 82→        maxCacheSizeBytes = newCacheSizeBytes;
 83→        if (shrink) {
 84→            log.debug("Cache size was shrunk to {}", newCacheSizeBytes);
 85→            if (caches.values().isEmpty()) {
